    // <img class='boardsign' src='https://npm.elemecdn.com/anzhiyu-blog@2.0.4/img/badge/zt-上班摸鱼中.svg' title='距离月入25k也就还差一个大佬带我~'>
    // <img class='boardsign' src='https://npm.elemecdn.com/anzhiyu-blog@2.0.4/img/badge/zt-下班啦.svg' title='下班了就该开开心心的玩耍，嘿嘿~'>
      ? `<span class='textTip'> <br> 本站居然运行了 ${dnum} 天</span><span id='runtime'> ${hnum} 小时 ${mnum} 分 ${snum} 秒 </span> <i class='fas fa-heartbeat' style='color:red'></i>`
      : `<span class='textTip'> <br> 本站居然运行了 ${dnum} 天</span><span id='runtime'> ${hnum} 小时 ${mnum} 分 ${snum} 秒 </span> <i class='fas fa-heartbeat' style='color:red'></i>`),
    document.getElementById("workboard") && (document.getElementById("workboard").innerHTML = currentTimeHtml);
}
setInterval(() => {
  createtime();
}, 250);

