创建`gulpfile.js`
在 Hexo 的根目录，创建一个`gulpfile.js`文件,打开`[Blogroot]/gulpfile.js`,

```
JAVASCRIPT/*
* @Description: gulp
* @Author: 安知鱼
* @Email: 2268025923@qq.com
* @Date: 2022-02-22 11:22:57
* @LastEditTime: 2022-08-18 12:24:11
* @LastEditors: 安知鱼
*/
import gulp from "gulp";
import cleanCSS from "gulp-clean-css";
import htmlmin from "gulp-htmlmin";
import htmlclean from "gulp-htmlclean";
import workbox from "workbox-build";
import fontmin from "gulp-fontmin";

// 若使用babel压缩js，则取消下方注释，并注释terser的代码
// var uglify = require('gulp-uglify');
// var babel = require('gulp-babel');

// 若使用terser压缩js
import terser from "gulp-terser";

//pwa
gulp.task("generate-service-worker", () => {
 return workbox.injectManifest({
   swSrc: "./sw-template.js",
   swDest: "./public/sw.js",
   globDirectory: "./public",
   globPatterns: [
     // 缓存所有以下类型的文件，极端不推荐
     // "**/*.{html,css,js,json,woff2,xml}"
     // 推荐只缓存404，主页和主要样式和脚本。
     "404.html",
     "index.html",
     "js/main.js",
     "css/index.css",
   ],
   modifyURLPrefix: {
     "": "./",
   },
 });
});

//minify js babel
// 若使用babel压缩js，则取消下方注释，并注释terser的代码
// gulp.task('compress', () =>
//   gulp.src(['./public/**/*.js', '!./public/**/*.min.js'])
// 		.pipe(babel({
// 			presets: ['@babel/preset-env']
// 		}))
//     .pipe(uglify().on('error', function(e){
//       console.log(e);
//     }))
// 		.pipe(gulp.dest('./public'))
// );

// minify js - gulp-tester
// 若使用terser压缩js
gulp.task("compress", () =>
 gulp
   .src([
     "./public/**/*.js",
     "!./public/**/*.min.js",
     "!./public/js/custom/galmenu.js",
     "!./public/js/custom/gitcalendar.js",
   ])
   .pipe(terser())
   .pipe(gulp.dest("./public"))
);

//css
gulp.task("minify-css", () => {
 return gulp
   .src("./public/**/*.css")
   .pipe(
     cleanCSS({
       compatibility: "ie11",
     })
   )
   .pipe(gulp.dest("./public"));
});

// 压缩 public 目录内 html
gulp.task("minify-html", () => {
 return gulp
   .src("./public/**/*.html")
   .pipe(htmlclean())
   .pipe(
     htmlmin({
       removeComments: true, //清除 HTML 註释
       collapseWhitespace: true, //压缩 HTML
       collapseBooleanAttributes: true, //省略布尔属性的值 <input checked="true"/> ==> <input />
       removeEmptyAttributes: true, //删除所有空格作属性值 <input id="" /> ==> <input />
       removeScriptTypeAttributes: true, //删除 <script> 的 type="text/javascript"
       removeStyleLinkTypeAttributes: true, //删除 <style> 和 <link> 的 type="text/css"
       minifyJS: true, //压缩页面 JS
       minifyCSS: true, //压缩页面 CSS
       minifyURLs: true,
     })
   )
   .pipe(gulp.dest("./public"));
});

//压缩字体
function minifyFont(text, cb) {
 gulp
   .src("./public/fonts/*.ttf") //原字体所在目录
   .pipe(
     fontmin({
       text: text,
     })
   )
   .pipe(gulp.dest("./public/fontsdest/")) //压缩后的输出目录
   .on("end", cb);
}

gulp.task("mini-font", cb => {
 var buffers = [];
 gulp
   .src(["./public/**/*.html"]) //HTML文件所在目录请根据自身情况修改
   .on("data", function (file) {
     buffers.push(file.contents);
   })
   .on("end", function () {
     var text = Buffer.concat(buffers).toString("utf-8");
     minifyFont(text, cb);
   });
});

// 执行 gulp 命令时执行的任务
gulp.task(
 "default",
 gulp.series("generate-service-worker", gulp.parallel("compress", "minify-html", "minify-css", "mini-font"))
);
```

